# SNS Topic Module
# This module creates an SNS topic with optional email subscriptions

resource "aws_sns_topic" "this" {
  name         = var.topic_name
  display_name = var.display_name

  tags = var.tags
}

# Create email subscriptions
resource "aws_sns_topic_subscription" "email" {
  for_each = toset(var.email_addresses)

  topic_arn = aws_sns_topic.this.arn
  protocol  = "email"
  endpoint  = each.value

  # Email subscriptions require manual confirmation
  # Terraform will show them as created, but they won't be active until confirmed
}

# Topic access policy
resource "aws_sns_topic_policy" "this" {
  arn = aws_sns_topic.this.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "${var.topic_name}-policy"
    Statement = [
      {
        Sid    = "AllowCloudWatchToPublish"
        Effect = "Allow"
        Principal = {
          Service = "cloudwatch.amazonaws.com"
        }
        Action = [
          "SNS:Publish"
        ]
        Resource = aws_sns_topic.this.arn
      }
    ]
  })
}

# Terraform Cloud Configuration
variable "terraform_organization" {
  description = "Terraform Cloud organization name"
  type        = string
  default     = "PetLabCo"
}

variable "terraform_workspace" {
  description = "Terraform Cloud workspace name"
  type        = string
  default     = "petlab-frontend-infra-labs"
}

# Environment Configuration
variable "environment" {
  description = "The environment name"
  type        = string
  default     = "labs"
}

variable "region" {
  description = "The AWS region"
  type        = string
  default     = "us-east-1"
}

# SNS Configuration
variable "sns_topic_arn" {
  description = "The ARN of the SNS topic for alarm notifications"
  type        = string
  default     = "arn:aws:sns:us-east-1:154805902702:labs-alarms"
}

# ECS Services List
variable "ecs_services" {
  description = "List of ECS services to monitor"
  type = list(object({
    service_name = string
    cluster_name = string

    # Optional service-specific overrides
    enable_alb_alarms        = optional(bool, false)
    target_group_arn_suffix  = optional(string, "")
    load_balancer_arn_suffix = optional(string, "")
    cpu_high_threshold       = optional(number)
    cpu_low_threshold        = optional(number)
    memory_high_threshold    = optional(number)
    min_healthy_tasks        = optional(number)
    response_time_threshold  = optional(number)
    error_rate_threshold_5xx = optional(number)
    error_rate_threshold_4xx = optional(number)
  }))

  default = [
    # Auth Services
    {
      service_name = "auth-labs-us"
      cluster_name = "auth-us-labs-cluster"
    },

    # Strapi Services
    {
      service_name          = "strapi-blue-us-dev"
      cluster_name          = "strapi-blue-us-dev"
      cpu_high_threshold    = 70
      memory_high_threshold = 75
    },
    {
      service_name          = "strapi-green-us-dev"
      cluster_name          = "strapi-green-us-dev"
      cpu_high_threshold    = 70
      memory_high_threshold = 75
    },
    {
      service_name          = "strapi-cap-blue-us-dev"
      cluster_name          = "strapi-cap-blue-us-dev"
      cpu_high_threshold    = 70
      memory_high_threshold = 75
    },
    {
      service_name          = "strapi-presell-green-us-dev"
      cluster_name          = "strapi-presell-green-us-dev"
      cpu_high_threshold    = 70
      memory_high_threshold = 75
    },
    {
      service_name          = "strapi-cap-green-us-dev"
      cluster_name          = "strapi-cap-green-us-dev"
      cpu_high_threshold    = 70
      memory_high_threshold = 75
    }
  ]
}

# Feature Toggles
variable "enable_low_cpu_alarm" {
  description = "Enable low CPU utilization alarms for cost optimization in labs"
  type        = bool
  default     = true
}

# Default Thresholds for Labs Environment
variable "default_cpu_high_threshold" {
  description = "Default high CPU threshold for labs (lower for cost optimization)"
  type        = number
  default     = 70
}

variable "default_cpu_low_threshold" {
  description = "Default low CPU threshold for labs"
  type        = number
  default     = 5
}

variable "default_memory_high_threshold" {
  description = "Default high memory threshold for labs"
  type        = number
  default     = 75
}

variable "default_min_healthy_tasks" {
  description = "Default minimum healthy tasks for labs"
  type        = number
  default     = 1
}

variable "default_response_time_threshold" {
  description = "Default response time threshold for labs (more lenient)"
  type        = number
  default     = 3.0
}

variable "default_error_rate_threshold_5xx" {
  description = "Default 5xx error threshold for labs (higher tolerance)"
  type        = number
  default     = 20
}

variable "default_error_rate_threshold_4xx" {
  description = "Default 4xx error threshold for labs (higher tolerance)"
  type        = number
  default     = 100
}

# Evaluation Periods and Timing
variable "cpu_evaluation_periods" {
  description = "Number of periods for CPU alarm evaluation"
  type        = number
  default     = 2
}

variable "cpu_period" {
  description = "Period in seconds for CPU metrics"
  type        = number
  default     = 300
}

variable "memory_evaluation_periods" {
  description = "Number of periods for memory alarm evaluation"
  type        = number
  default     = 2
}

variable "memory_period" {
  description = "Period in seconds for memory metrics"
  type        = number
  default     = 300
}

variable "task_count_evaluation_periods" {
  description = "Number of periods for task count alarm evaluation"
  type        = number
  default     = 1
}

variable "task_count_period" {
  description = "Period in seconds for task count metrics"
  type        = number
  default     = 60
}

variable "response_time_evaluation_periods" {
  description = "Number of periods for response time alarm evaluation"
  type        = number
  default     = 2
}

variable "response_time_period" {
  description = "Period in seconds for response time metrics"
  type        = number
  default     = 300
}

variable "error_rate_evaluation_periods" {
  description = "Number of periods for error rate alarm evaluation"
  type        = number
  default     = 2
}

variable "error_rate_period" {
  description = "Period in seconds for error rate metrics"
  type        = number
  default     = 300
}

# S3 Buckets List
variable "s3_buckets" {
  description = "List of S3 buckets to create"
  type = list(object({
    bucket_name   = string
    force_destroy = optional(bool, false)

    # Optional bucket-specific overrides
    versioning_enabled         = optional(bool, true)
    enable_lifecycle           = optional(bool, false)
    transition_to_ia_days      = optional(number, 30)
    transition_to_glacier_days = optional(number, 90)
    expiration_days            = optional(number, 0)
    kms_key_id                 = optional(string, "")

    # CORS rules for web assets
    cors_rules = optional(list(object({
      allowed_methods = list(string)
      allowed_origins = list(string)
      allowed_headers = optional(list(string))
      max_age_seconds = optional(number)
    })), [])
  }))

  default = [
    {
      bucket_name        = "visual-regression"
      force_destroy      = true
      enable_lifecycle   = false
      versioning_enabled = false
      cors_rules = [
        {
          allowed_methods = ["GET", "HEAD", "PUT", "POST"]
          allowed_origins = ["*"]
          allowed_headers = ["*"]
          max_age_seconds = 3600
        }
      ]
    }
  ]
}

# Default Tags
variable "default_tags" {
  description = "Default tags for all resources"
  type        = map(string)
  default = {
    Terraform   = "true"
    Environment = "labs"
    Region      = "us-east-1"
    ManagedBy   = "terraform-aws-infrastructure"
    Team        = "frontend"
    Technology  = "strapi"
    Project     = "cap"
  }
}

